import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F04_業外收支純度與收益質量_投資研究員.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F04_業外收支純度與收益質量_投資研究員.md"}'),n={name:"審計報告庫/財務審計/6903_巨漢/20260502/F04_業外收支純度與收益質量_投資研究員.md"};function i(l,a,_,s,h,d){return e(),o("div",null,[...a[0]||(a[0]=[r('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司本期損益中，業外收支（非核心業務）的佔比為何？獲利純度是否受到一次性項目的顯著干擾？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢業外收支極低（佔稅前淨利 1.4%-4.3%），獲利純度優異，幾乎沒有非核心業務干擾。營業利益佔稅前淨利 95% 以上，屬於「純度極高」的獲利結構，無一次性項目或業外操作的疑慮。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（優）。業外收支穩定且佔比低，無資產處分、匯率干擾或投資損益等一次性項目。利空：業外偏低是「沒問題」，但也反映公司資金運用保守（無積極理財或轉投資），現金使用效率有待觀察。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>業外佔比</strong>：2023 年業外收入 1,480 萬（稅前比 1.4%）、2024 年 3,270 萬（4.3%）、2025 年 3,010 萬（3.4%）。主為利息收入與少數租金收入，無重大資產處分或金融資產評價損益。</p></li><li><p><strong>核心獲利佔比</strong>：營業利益佔稅前淨利比值：2023 年 98.6%、2024 年 95.7%、2025 年 96.6%。連續 3 年高於 95%，代表每 100 元稅前淨利中有 95 元以上來自本業。扣非後 EPS 與帳面 EPS 幾乎無差異。</p></li><li><p><strong>業外異常偵測</strong>：無巨額資產處分、無子公司減損、無衍生性商品評價損失。唯一的業外項目為銀行利息收入（約 1,500-2,000 萬/年）及處分不動產、廠房及設備之零星損益。業外收支對報告主體的判斷不構成任何影響。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>不存在業外陷阱</strong>：許多公司會透過處分資產或轉投資收益美化財報，巨漢沒有這個問題。獲利 95%+ 來自本業，EPS 的品質極高，這是明顯的加分項。</li><li><strong>現金運用保守的利空</strong>：業外收入幾乎都是利息收入，代表帳上大量現金僅放在銀行定存（約 10-15 億），沒有積極的資金運用。若管理層能將多餘現金用於併購或擴產，股東權益報酬率（ROE）可望進一步提升。</li><li><strong>風險：低業外 ≠ 低風險</strong>：業外低代表公司業務單純，但也意味著缺乏多元化的收入來源。若本業（半導體廠務工程）景氣反轉，公司沒有業外保護傘可緩衝獲利衝擊。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind：TaiwanStockFinancialStatements（2023-2025 TotalNonoperatingIncomeAndExpense）</li></ul>',12)])])}const u=t(n,[["render",i]]);export{p as __pageData,u as default};
